CREATE TEMP TABLE bw_sw1_material_keys AS
SELECT DISTINCT
    catchment_name,
    nuts_or_lau_id,
    collection_system_name,
    waste_category_name,
    valid_from
FROM bw_sw1_material_rows;

SELECT COUNT(*) AS workbook_collection_keys
FROM bw_sw1_material_keys;

CREATE TEMP TABLE bw_sw1_target_collections AS
SELECT
    c.id AS collection_id,
    catchment.name AS catchment_name,
    COALESCE(nuts.nuts_id, lau.lau_id, '') AS nuts_or_lau_id,
    cs.name AS collection_system_name,
    wc.name AS waste_category_name,
    c.valid_from
FROM soilcom_collection c
JOIN maps_catchment catchment ON catchment.id = c.catchment_id
LEFT JOIN maps_nutsregion nuts ON nuts.region_ptr_id = catchment.region_id
LEFT JOIN maps_lauregion lau ON lau.region_ptr_id = catchment.region_id
JOIN soilcom_collectionsystem cs ON cs.id = c.collection_system_id
JOIN soilcom_wastecategory wc ON wc.id = c.waste_category_id
JOIN bw_sw1_material_keys keys
    ON cs.name = keys.collection_system_name
   AND wc.name = keys.waste_category_name
   AND c.valid_from = keys.valid_from
   AND (
        (keys.nuts_or_lau_id <> '' AND COALESCE(nuts.nuts_id, lau.lau_id, '') = keys.nuts_or_lau_id)
        OR (keys.nuts_or_lau_id = '' AND catchment.name = keys.catchment_name)
   );

SELECT COUNT(*) AS matched_collections
FROM bw_sw1_target_collections;

SELECT
    keys.catchment_name,
    keys.nuts_or_lau_id,
    keys.collection_system_name,
    keys.waste_category_name,
    keys.valid_from
FROM bw_sw1_material_keys keys
LEFT JOIN bw_sw1_target_collections target
    ON target.collection_system_name = keys.collection_system_name
   AND target.waste_category_name = keys.waste_category_name
   AND target.valid_from = keys.valid_from
   AND (
        (keys.nuts_or_lau_id <> '' AND target.nuts_or_lau_id = keys.nuts_or_lau_id)
        OR (keys.nuts_or_lau_id = '' AND target.catchment_name = keys.catchment_name)
   )
WHERE target.collection_id IS NULL
ORDER BY
    keys.valid_from,
    keys.nuts_or_lau_id,
    keys.catchment_name,
    keys.collection_system_name,
    keys.waste_category_name;

SELECT
    rows.side,
    rows.material_name,
    COUNT(*) AS occurrences
FROM bw_sw1_material_rows rows
LEFT JOIN materials_basematerial material ON material.name = rows.material_name
WHERE material.id IS NULL
GROUP BY rows.side, rows.material_name
ORDER BY rows.side, rows.material_name;

CREATE TEMP TABLE bw_sw1_material_rows_resolved AS
SELECT DISTINCT
    target.collection_id,
    rows.side,
    material.id AS material_id
FROM bw_sw1_material_rows rows
JOIN bw_sw1_target_collections target
    ON target.collection_system_name = rows.collection_system_name
   AND target.waste_category_name = rows.waste_category_name
   AND target.valid_from = rows.valid_from
   AND (
        (rows.nuts_or_lau_id <> '' AND target.nuts_or_lau_id = rows.nuts_or_lau_id)
        OR (rows.nuts_or_lau_id = '' AND target.catchment_name = rows.catchment_name)
   )
JOIN materials_basematerial material
    ON material.name = rows.material_name;

SELECT
    side,
    COUNT(*) AS expected_links
FROM bw_sw1_material_rows_resolved
GROUP BY side
ORDER BY side;

INSERT INTO soilcom_collection_allowed_materials (collection_id, material_id)
SELECT resolved.collection_id, resolved.material_id
FROM bw_sw1_material_rows_resolved resolved
LEFT JOIN soilcom_collection_allowed_materials existing
    ON existing.collection_id = resolved.collection_id
   AND existing.material_id = resolved.material_id
WHERE resolved.side = 'allowed'
  AND existing.id IS NULL;

INSERT INTO soilcom_collection_forbidden_materials (collection_id, material_id)
SELECT resolved.collection_id, resolved.material_id
FROM bw_sw1_material_rows_resolved resolved
LEFT JOIN soilcom_collection_forbidden_materials existing
    ON existing.collection_id = resolved.collection_id
   AND existing.material_id = resolved.material_id
WHERE resolved.side = 'forbidden'
  AND existing.id IS NULL;

SELECT
    resolved.side,
    COUNT(*) AS remaining_missing_links
FROM bw_sw1_material_rows_resolved resolved
LEFT JOIN soilcom_collection_allowed_materials allowed_existing
    ON allowed_existing.collection_id = resolved.collection_id
   AND allowed_existing.material_id = resolved.material_id
   AND resolved.side = 'allowed'
LEFT JOIN soilcom_collection_forbidden_materials forbidden_existing
    ON forbidden_existing.collection_id = resolved.collection_id
   AND forbidden_existing.material_id = resolved.material_id
   AND resolved.side = 'forbidden'
WHERE (resolved.side = 'allowed' AND allowed_existing.id IS NULL)
   OR (resolved.side = 'forbidden' AND forbidden_existing.id IS NULL)
GROUP BY resolved.side
ORDER BY resolved.side;

COMMIT;
